    for(int i=1;i<=N;i++) adj[i]=new ArrayList<>();
    // store windows per edge: we keep list of edges each with windows
    List<int[]>[] edgeList=new List[N+1];
    for(int i=1;i<=N;i++) edgeList[i]=new ArrayList<>();
    List<long[]> allWin=new ArrayList<>();
